#include <stdio.h>
#include <stdlib.h>

long long maxSumK(long long *a,int n,int k){
    long long cur=0;
    for(int i=0;i<k;i++) cur+=a[i];
    long long best=cur;
    for(int i=1;i<=k;i++){
        cur=cur-a[i-1]+a[n-i];
        if(cur>best) best=cur;
    }
    return best;
}

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int n,k; scanf("%d %d",&n,&k);
        long long *arr=malloc(sizeof(long long)*n);
        for(int i=0;i<n;i++) scanf("%lld",&arr[i]);
        printf("%lld\n",maxSumK(arr,n,k));
        free(arr);
    }
    return 0;
}

