long long maxSumK(const vector<long long>& a,int k){
    int n=a.size();
    long long cur=0;
    for(int i=0;i<k;i++) cur+=a[i];
    long long best=cur;
    for(int i=1;i<=k;i++){
        cur=cur-a[i-1]+a[n-i];
        best=max(best,cur);
    }
    return best;
}

